# security/injection_detector.py
import re
from dataclasses import dataclass

@dataclass
class InjectionCheckResult:
    is_suspicious: bool
    matched_patterns: list[str]
    risk_level: str  # "low" | "medium" | "high"

# Known injection patterns — not exhaustive; complement with semantic checking
INJECTION_PATTERNS = {
    "ignore_instructions": re.compile(
        r'ignore\s+(all\s+)?(previous|prior|above|earlier)\s+instructions?',
        re.IGNORECASE,
    ),
    "new_instructions": re.compile(
        r'(new|updated|revised)\s+instructions?\s*:',
        re.IGNORECASE,
    ),
    "system_prompt_override": re.compile(
        r'(system\s+prompt|system\s+message)\s*=',
        re.IGNORECASE,
    ),
    "role_override": re.compile(
        r'you\s+are\s+now\s+(?:a|an|the)\s+(?!support|assistant)',
        re.IGNORECASE,
    ),
    "delimiter_injection": re.compile(
        r'</?(document|context|system|instruction)>',
        re.IGNORECASE,
    ),
}

def check_for_injection(text: str) -> InjectionCheckResult:
    matches = []
    for pattern_name, pattern in INJECTION_PATTERNS.items():
        if pattern.search(text):
            matches.append(pattern_name)

    if not matches:
        return InjectionCheckResult(False, [], "low")

    risk = "high" if len(matches) >= 2 else "medium"
    return InjectionCheckResult(True, matches, risk)

def wrap_retrieved_content(doc_id: str, content: str) -> str:
    # Ensure retrieved content cannot escape its XML container
    # Strip any existing delimiter tags from content before wrapping
    stripped = re.sub(r'</?document[^>]*>', '', content)
    return f'<document id="{doc_id}">{stripped}</document>'

# http_client.py — secure HTTP client configuration
import httpx
import os

def create_anthropic_client() -> httpx.AsyncClient:
    proxy_url = os.environ.get("HTTPS_PROXY") or os.environ.get("https_proxy")
    if not proxy_url:
        raise RuntimeError(
            "HTTPS_PROXY environment variable must be set; "
            "direct outbound connections to Anthropic API are not permitted"
        )

    return httpx.AsyncClient(
        proxies={"https://": proxy_url},
        verify=True,          # NEVER set to False
        timeout=httpx.Timeout(connect=5.0, read=60.0, write=10.0, pool=5.0),
        limits=httpx.Limits(max_connections=50, max_keepalive_connections=20),
        headers={
            "User-Agent": f"LearnWithDeiva-Integration/1.0",
        },
    )
